from dataclasses import dataclass, asdict
from datetime import datetime
from uuid import UUID, uuid4
import json

# Domain Events
@dataclass
class DomainEvent:
    aggregate_id: UUID
    event_id: UUID
    event_type: str
    timestamp: datetime
    version: int
    payload: Dict[str, Any]

    def to_dict(self) -> Dict:
        return {
            'aggregate_id': str(self.aggregate_id),
            'event_id': str(self.event_id),
            'event_type': self.event_type,
            'timestamp': self.timestamp.isoformat(),
            'version': self.version,
            'payload': self.payload
        }

# Aggregate Root
class AggregateRoot(ABC):
    """Base class for event-sourced aggregates."""

    def __init__(self, aggregate_id: UUID):
        self._id = aggregate_id
        self._version = 0
        self._uncommitted_events: List[DomainEvent] = []
        self._is_replaying = False

    @property
    def id(self) -> UUID:
        return self._id

    @property
    def version(self) -> int:
        return self._version

    @property
    def uncommitted_events(self) -> List[DomainEvent]:
        return self._uncommitted_events.copy()

    def apply_event(self, event: DomainEvent):
        """Apply event to mutate state."""
        handler = getattr(self, f'_on_{event.event_type}', None)
        if handler:
            handler(event.payload)

        if not self._is_replaying:
            self._uncommitted_events.append(event)

        self._version = event.version

    def _create_event(self, event_type: str, payload: Dict[str, Any]) -> DomainEvent:
        return DomainEvent(
            aggregate_id=self._id,
            event_id=uuid4(),
            event_type=event_type,
            timestamp=datetime.utcnow(),
            version=self._version + 1,
            payload=payload
        )

    def load_from_history(self, events: List[DomainEvent]):
        """Rehydrate aggregate from event history."""
        self._is_replaying = True
        for event in sorted(events, key=lambda e: e.version):
            self.apply_event(event)
        self._is_replaying = False
        self._uncommitted_events = []

    def mark_committed(self):
        """Clear uncommitted events after persistence."""
        self._uncommitted_events = []

# Command Handler
class CommandHandler(ABC):
    """Base class for command handlers."""

    @abstractmethod
    def handle(self, command: Any) -> Any:
        pass

# Query Handler
class QueryHandler(ABC):
    """Base class for query handlers (read model)."""

    @abstractmethod
    def handle(self, query: Any) -> Any:
        pass

# Event Store
class EventStore:
    """Stores and retrieves domain events."""

    def __init__(self):
        self._streams: Dict[UUID, List[DomainEvent]] = {}

    def append(self, aggregate_id: UUID, events: List[DomainEvent], expected_version: int):
        """Append events with optimistic concurrency check."""
        stream = self._streams.get(aggregate_id, [])

        if len(stream) != expected_version:
            raise ConcurrencyException(
                f"Expected version {expected_version}, found {len(stream)}"
            )

        if aggregate_id not in self._streams:
            self._streams[aggregate_id] = []

        self._streams[aggregate_id].extend(events)

    def get_events(self, aggregate_id: UUID, from_version: int = 0) -> List[DomainEvent]:
        """Get events for an aggregate."""
        stream = self._streams.get(aggregate_id, [])
        return [e for e in stream if e.version > from_version]

    def get_all_events(self, after_position: int = 0) -> List[DomainEvent]:
        """Get all events (for projections)."""
        all_events = []
        for stream in self._streams.values():
            all_events.extend(stream)
        return sorted(all_events, key=lambda e: e.timestamp)[after_position:]

class ConcurrencyException(Exception):
    pass

# Example: Order Aggregate
class Order(AggregateRoot):
    def __init__(self, order_id: UUID, customer_id: str):
        super().__init__(order_id)
        self._customer_id = customer_id
        self._items: List[Dict] = []
        self._status = "pending"
        self._total = 0.0

    @classmethod
    def create(cls, order_id: UUID, customer_id: str) -> 'Order':
        order = cls(order_id, customer_id)
        event = order._create_event('order_created', {
            'customer_id': customer_id,
            'created_at': datetime.utcnow().isoformat()
        })
        order.apply_event(event)
        return order

    def add_item(self, product_id: str, quantity: int, price: float):
        event = self._create_event('item_added', {
            'product_id': product_id,
            'quantity': quantity,
            'price': price
        })
        self.apply_event(event)

    def confirm(self):
        if self._status != "pending":
            raise ValueError("Order already processed")

        event = self._create_event('order_confirmed', {
            'confirmed_at': datetime.utcnow().isoformat(),
            'total': self._total
        })
        self.apply_event(event)

    # Event handlers
    def _on_order_created(self, payload):
        self._customer_id = payload['customer_id']
        self._status = "pending"

    def _on_item_added(self, payload):
        self._items.append(payload)
        self._total += payload['quantity'] * payload['price']

    def _on_order_confirmed(self, payload):
        self._status = "confirmed"
