// src/products/products.service.ts
import {
  Injectable,
  NotFoundException,
  BadRequestException,
  Inject,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository, Like, FindManyOptions } from 'typeorm';
import { CACHE_MANAGER } from '@nestjs/cache-manager';
import { Cache } from 'cache-manager';
import { Product } from './entities/product.entity';
import { CreateProductDto } from './dto/create-product.dto';
import { UpdateProductDto } from './dto/update-product.dto';
import { PaginationDto } from '../common/dto/pagination.dto';
import { EventEmitter2 } from '@nestjs/event-emitter';

export interface PaginatedResult<T> {
  data: T[];
  total: number;
  page: number;
  limit: number;
  totalPages: number;
}

@Injectable()
export class ProductsService {
  constructor(
    @InjectRepository(Product)
    private productRepository: Repository<Product>,
    @Inject(CACHE_MANAGER) private cacheManager: Cache,
    private eventEmitter: EventEmitter2,
  ) {}

  async findAll(options: {
    page: number;
    limit: number;
    category?: string;
    search?: string;
  }): Promise<PaginatedResult<Product>> {
    const { page, limit, category, search } = options;
    const skip = (page - 1) * limit;

    const where: FindManyOptions<Product>['where'] = {};

    if (category) {
      where.category = { slug: category };
    }

    if (search) {
      where.name = Like(`%${search}%`);
    }

    const [data, total] = await this.productRepository.findAndCount({
      where,
      relations: ['category'],
      skip,
      take: limit,
      order: { createdAt: 'DESC' },
    });

    return {
      data,
      total,
      page,
      limit,
      totalPages: Math.ceil(total / limit),
    };
  }

  async findOne(id: number): Promise<Product> {
    // Check cache first
    const cacheKey = `product_${id}`;
    let product = await this.cacheManager.get<Product>(cacheKey);

    if (!product) {
      product = await this.productRepository.findOne({
        where: { id },
        relations: ['category', 'reviews'],
      });

      if (!product) {
        throw new NotFoundException(`Product with ID ${id} not found`);
      }

      // Cache for 5 minutes
      await this.cacheManager.set(cacheKey, product, 300 * 1000);
    }

    return product;
  }

  async create(createProductDto: CreateProductDto): Promise<Product> {
    // Check for duplicate SKU
    const existing = await this.productRepository.findOne({
      where: { sku: createProductDto.sku },
    });

    if (existing) {
      throw new BadRequestException(
        `Product with SKU ${createProductDto.sku} already exists`,
      );
    }

    const product = this.productRepository.create(createProductDto);
    const saved = await this.productRepository.save(product);

    // Emit event for other services
    this.eventEmitter.emit('product.created', saved);

    return saved;
  }

  async update(
    id: number,
    updateProductDto: UpdateProductDto,
  ): Promise<Product> {
    const product = await this.findOne(id);

    // Update fields
    Object.assign(product, updateProductDto);

    const updated = await this.productRepository.save(product);

    // Invalidate cache
    await this.cacheManager.del(`product_${id}`);
    await this.cacheManager.del('products_list');

    // Emit event
    this.eventEmitter.emit('product.updated', updated);

    return updated;
  }

  async remove(id: number): Promise<void> {
    const product = await this.findOne(id);
    await this.productRepository.remove(product);

    // Invalidate cache
    await this.cacheManager.del(`product_${id}`);
    await this.cacheManager.del('products_list');

    this.eventEmitter.emit('product.deleted', { id });
  }

  async updateStock(id: number, quantity: number): Promise<void> {
    const product = await this.findOne(id);

    if (product.stock + quantity < 0) {
      throw new BadRequestException('Insufficient stock');
    }

    product.stock += quantity;
    await this.productRepository.save(product);

    // Invalidate cache
    await this.cacheManager.del(`product_${id}`);
  }
}

