from rest_framework import serializers
from django.contrib.auth.models import User
from .models import Product, Category, Order, OrderItem

class CategorySerializer(serializers.ModelSerializer):
    """Category serializer with nested children."""
    children = serializers.SerializerMethodField()
    product_count = serializers.IntegerField(source='products.count', read_only=True)

    class Meta:
        model = Category
        fields = ['id', 'name', 'slug', 'parent', 'children', 'product_count']
        read_only_fields = ['id']

    def get_children(self, obj):
        if obj.children.exists():
            return CategorySerializer(
                obj.children.filter(is_active=True),
                many=True
            ).data
        return []

class ProductListSerializer(serializers.ModelSerializer):
    """Lightweight product serializer for lists."""
    category_name = serializers.CharField(source='category.name', read_only=True)

    class Meta:
        model = Product
        fields = [
            'id', 'name', 'slug', 'price', 'stock',
            'is_in_stock', 'category_name', 'created_at'
        ]

class ProductSerializer(serializers.ModelSerializer):
    """Detailed product serializer."""
    category = CategorySerializer(read_only=True)
    average_rating = serializers.SerializerMethodField()
    review_count = serializers.SerializerMethodField()

    class Meta:
        model = Product
        fields = [
            'id', 'name', 'slug', 'description', 'price',
            'stock', 'is_active', 'is_featured', 'sku',
            'weight', 'category', 'average_rating',
            'review_count', 'created_at', 'updated_at'
        ]
        read_only_fields = ['id', 'created_at', 'updated_at']

    def get_average_rating(self, obj):
        # Assuming Product has a related Rating model
        return obj.ratings.aggregate(Avg('score'))['score__avg'] or 0

