### Instruction:
Create a React hook for handling form state and validation.

### Response:
import { useState, useCallback } from 'react';

interface ValidationRules {
  [key: string]: {
    required?: boolean;
    minLength?: number;
    maxLength?: number;
    pattern?: RegExp;
    validate?: (value: any) => string | undefined;
  };
}

export function useForm<T extends Record<string, any>>(
  initialValues: T,
  validationRules?: ValidationRules
) {
  const [values, setValues] = useState<T>(initialValues);
  const [errors, setErrors] = useState<Partial<Record<keyof T, string>>>({});
  const [touched, setTouched] = useState<Partial<Record<keyof T, boolean>>>({});

  const validate = useCallback((fieldValues: T): boolean => {
    if (!validationRules) return true;

    const newErrors: Partial<Record<keyof T, string>> = {};

    Object.keys(validationRules).forEach((field) => {
      const value = fieldValues[field];
      const rules = validationRules[field];

      if (rules.required && !value) {
        newErrors[field as keyof T] = 'This field is required';
      } else if (rules.minLength && value.length < rules.minLength) {
        newErrors[field as keyof T] = `Minimum length is ${rules.minLength}`;
      } else if (rules.maxLength && value.length > rules.maxLength) {
        newErrors[field as keyof T] = `Maximum length is ${rules.maxLength}`;
      } else if (rules.pattern && !rules.pattern.test(value)) {
        newErrors[field as keyof T] = 'Invalid format';
      } else if (rules.validate) {
        const error = rules.validate(value);
        if (error) newErrors[field as keyof T] = error;
      }
    });

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  }, [validationRules]);

  const handleChange = useCallback((field: keyof T, value: any) => {
    setValues(prev => ({ ...prev, [field]: value }));
    if (touched[field]) {
      validate({ ...values, [field]: value } as T);
    }
  }, [values, touched, validate]);

  const handleBlur = useCallback((field: keyof T) => {
    setTouched(prev => ({ ...prev, [field]: true }));
    validate(values);
  }, [values, validate]);

  const handleSubmit = useCallback((onSubmit: (values: T) => void) => {
    setTouched(Object.keys(values).reduce((acc, key) => ({
      ...acc,
      [key]: true
    }), {} as Record<keyof T, boolean>));

    if (validate(values)) {
      onSubmit(values);
    }
  }, [values, validate]);

  const reset = useCallback(() => {
    setValues(initialValues);
    setErrors({});
    setTouched({});
  }, [initialValues]);

  return {
    values,
    errors,
    touched,
    handleChange,
    handleBlur,
    handleSubmit,
    reset,
    isValid: Object.keys(errors).length === 0
  };
}

// Usage
function LoginForm() {
  const form = useForm(
    { email: '', password: '' },
    {
      email: {
        required: true,
        pattern: /^[^\s@]+@[^\s@]+\.[^\s@]+$/
      },
      password: {
        required: true,
        minLength: 8
      }
    }
  );

  return (
    <form onSubmit={(e) => {
      e.preventDefault();
      form.handleSubmit(console.log);
    }}>
      <input
        value={form.values.email}
        onChange={(e) => form.handleChange('email', e.target.value)}
        onBlur={() => form.handleBlur('email')}
      />
