## Password Security Best Practices

### NEVER do this:
```python
# вқҢ Storing plain text
password = 'user123'
db.store(password)

# вқҢ Using weak hashing (MD5, SHA1)
import hashlib
hash = hashlib.md5(password.encode()).hexdigest()

# вқҢ Simple hashing without salt
hash = hashlib.sha256(password.encode()).hexdigest()
```

### вң… Correct Approach: bcrypt
```python
import bcrypt

def hash_password(password: str) -> str:
    """Hash a password using bcrypt."""
    # Generate salt and hash
    salt = bcrypt.gensalt(rounds=12)  # Work factor
    hashed = bcrypt.hashpw(password.encode('utf-8'), salt)
    return hashed.decode('utf-8')

def verify_password(password: str, hashed: str) -> bool:
    """Verify a password against its hash."""
    return bcrypt.checkpw(
        password.encode('utf-8'),
        hashed.encode('utf-8')
    )

# Usage
hashed = hash_password('user_password')
is_valid = verify_password('user_password', hashed)
```

### Using argon2 (Modern Alternative)
```python
from argon2 import PasswordHasher

ph = PasswordHasher(
    time_cost=3,      # Iterations
    memory_cost=65536, # 64 MB
    parallelism=1,    # Parallel threads
    hash_len=32,
    salt_len=16
)

def hash_password(password: str) -> str:
    return ph.hash(password)

def verify_password(password: str, hashed: str) -> bool:
    try:
        ph.verify(hashed, password)
        return True
    except:
        return False
```

