## Secure Session Management

### 1. Session Token Generation
```python
import secrets
import hashlib
from datetime import datetime, timedelta

class SessionManager:
    def __init__(self):
        self.sessions = {}  # Use Redis in production

    def create_session(self, user_id: str) -> str:
        """Create a secure session token."""
        # Generate cryptographically secure token
        token = secrets.token_urlsafe(32)

        # Store session data
        self.sessions[token] = {
            'user_id': user_id,
            'created_at': datetime.utcnow(),
            'expires_at': datetime.utcnow() + timedelta(hours=24),
            'ip_address': None,  # Set from request
            'user_agent': None   # Set from request
        }

        return token

    def validate_session(self, token: str, request_ip: str, user_agent: str) -> Optional[dict]:
        """Validate session and check for hijacking."""
        session = self.sessions.get(token)

        if not session:
            return None

        # Check expiration
        if datetime.utcnow() > session['expires_at']:
            del self.sessions[token]
            return None

        # Validate IP (optional - may break for mobile users)
        if session.get('ip_address') and session['ip_address'] != request_ip:
            # Potential session hijacking
            self.invalidate_session(token)
            return None

        return session

    def invalidate_session(self, token: str):
        """Logout - remove session."""
        self.sessions.pop(token, None)

    def rotate_token(self, old_token: str) -> Optional[str]:
        """Rotate session token after privilege changes."""
        session = self.sessions.get(old_token)
        if not session:
            return None

        # Create new token
        new_token = secrets.token_urlsafe(32)
        self.sessions[new_token] = session
        del self.sessions[old_token]

        return new_token
```

