app = Flask(__name__)

@app.route('/login')
def login():
    session_token = session_manager.create_session(user_id)

    response = make_response('Logged in')
    response.set_cookie(
        'session_token',
        session_token,
        httponly=True,      # Prevent XSS access
        secure=True,        # HTTPS only
        samesite='Strict',  # CSRF protection
        max_age=86400       # 24 hours
    )
    return response
